-- Anti-pattern: monotonic key hotspots all writes on one split
CREATE TABLE Orders (
  OrderId INT64 NOT NULL,      -- auto-increment: bad
  CustomerId INT64 NOT NULL,
  CreatedAt TIMESTAMP NOT NULL,
) PRIMARY KEY (OrderId);

-- Better: UUID key, and items interleaved with their order
CREATE TABLE Orders (
  OrderId STRING(36) NOT NULL,  -- UUID: writes spread across splits
  CustomerId INT64 NOT NULL,
  CreatedAt TIMESTAMP NOT NULL,
) PRIMARY KEY (OrderId);

CREATE TABLE OrderItems (
  OrderId STRING(36) NOT NULL,
  ItemId INT64 NOT NULL,
  Sku STRING(64) NOT NULL,
) PRIMARY KEY (OrderId, ItemId),
  INTERLEAVE IN PARENT Orders ON DELETE CASCADE;

